import java.util.*;
import java.util.stream.*;
public class CollectStream {
    public static void main(String[] args) {
        List<String> words = Arrays.asList("apple","banana","avocado","blueberry","apricot");
        List<String> aWords = words.stream()
            .filter(w -> w.startsWith("a"))
            .sorted()
            .collect(Collectors.toList());
        System.out.println(aWords);
        Map<Character,Long> freq = words.stream()
            .collect(Collectors.groupingBy(w -> w.charAt(0), Collectors.counting()));
        System.out.println(freq.get('a'));
        System.out.println(freq.get('b'));
    }
}
